    <script type="application/ld+json">
    {
        "@context": "https://schema.org",
        "@type": "DefinedTermSet",
        "name": "UK Company Registration Key Terms",
        "definedTerm": [
            {
                "@type": "DefinedTerm",
                "name": "UK Private Limited Company (Ltd)",
                "description": "Separate legal entity, limited liability, standard vehicle under the Companies Act 2006 for SMEs and foreign founders; minimum 1 director (any nationality, age 16+), 1 shareholder, GBP 1 paid-up share capital, UK registered office and PSC register."
            },
            {
                "@type": "DefinedTerm",
                "name": "Companies House",
                "description": "The UK's national company registrar - an executive agency of the Department for Business and Trade. Handles incorporation, Confirmation Statements, accounts filings and the PSC register."
            },
            {
                "@type": "DefinedTerm",
                "name": "ECCT Act 2023",
                "description": "Economic Crime and Corporate Transparency Act 2023 - landmark UK reform requiring identity verification for company officers and Persons with Significant Control plus enhanced Companies House powers to query and remove false data."
            },
            {
                "@type": "DefinedTerm",
                "name": "ID Verification (ECCT)",
                "description": "Mandatory identity check via Companies House One Login or an Authorised Corporate Service Provider (ACSP) - required from 18 November 2025 for new directors and PSCs."
            },
            {
                "@type": "DefinedTerm",
                "name": "ACSP",
                "description": "Authorised Corporate Service Provider - a regulated entity (typically an accountancy or law firm) that can carry out ID verification and file on behalf of clients under ECCT."
            },
            {
                "@type": "DefinedTerm",
                "name": "PSC Register",
                "description": "Persons with Significant Control register - mandatory disclosure of individuals or entities holding 25 percent or more of shares, voting rights or significant influence over the company."
            },
            {
                "@type": "DefinedTerm",
                "name": "Marginal Relief (UK CT)",
                "description": "Formula-based corporation tax relief for companies with profits between GBP 50,000 and GBP 250,000; gradually phases the tax rate from 19 percent to 25 percent (fraction 3/200; effective rate up to 26.5 percent per HMRC CTM03900)."
            },
            {
                "@type": "DefinedTerm",
                "name": "Confirmation Statement",
                "description": "Annual filing with Companies House confirming the company's public information is up to date; digital fee GBP 50 from 1 February 2026."
            },
            {
                "@type": "DefinedTerm",
                "name": "CT600",
                "description": "Corporation Tax return filed with HMRC within 12 months of the accounting period end; CT payment due 9 months and 1 day after period end."
            },
            {
                "@type": "DefinedTerm",
                "name": "MLI (Multilateral Convention)",
                "description": "Multilateral Convention to Implement Tax Treaty Related Measures to Prevent BEPS - in force for India from 1 October 2019; India-UK DTAA is a Covered Tax Agreement with PPT and revised preamble applicable from 1 April 2020 on the India side."
            },
            {
                "@type": "DefinedTerm",
                "name": "FEMA OI Rules 2022",
                "description": "Foreign Exchange Management (Overseas Investment) Rules 2022 effective 22 August 2022 - the India-side framework for outbound investment by Indian residents and companies."
            },
            {
                "@type": "DefinedTerm",
                "name": "Principal Purpose Test (PPT)",
                "description": "Anti-abuse rule under Article 7 of the MLI - treaty benefits denied where one of the principal purposes of an arrangement was tax benefit; CBDT Circular 01/2025 confirms PPT applies prospectively."
            }
        ]
    }
